//-------------------------------------------------------------------------
// 조회 조건 검증
//-------------------------------------------------------------------------
scwin.f_Validation = async function () {
    if (!await $c.gus.cfValidate([ed_coCd, ica_closeYm, ed_acqDtStDt, ed_acqDtEndDt])) {
        return false;
    }

    if ($c.gus.cfIsNull(ed_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ed_acqDtStDt.focus();
        return false;
    }

    if (!$c.gus.cfIsNull(ed_acqDtStDt.getValue()) && $c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
        await c.gus.cfAlertMsg(MSG_CM_WRN_003, ["취득일자"]);
        ed_acqDtEndDt.focus();
        return false;
    }

    // if (!$c.gus.cfIsNull(ed_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
    //     if (!$c.gus.cfValidateValue(ed_acqDtEndDt.getValue(),"minDate=" + ed_acqDtStDt.getValue())) {
    //         $c.gus.cfAlertMsg(MSG_CM_ERR_039);
    //         ed_acqDtStDt.focus();
    //         return false;
    //     }
    // }

    if (!$c.gus.cfIsNull(ed_acqDtStDt.getValue()) && !$c.gus.cfIsNull(ed_acqDtEndDt.getValue())) {
        if (WebSquare.date.dateDiff(ed_acqDtStDt.getValue(), ed_acqDtEndDt.getValue()) < 0) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
            ed_acqDtStDt.focus();
            return false;
        }
    }

    if (!await $c.gus.cfValidate([ed_srchAcctDeptCd, ed_srchAcctDeptNm,
        ed_srchFixedAsetNo, ed_srchFixedAsetNo2])) {
        return false;
    }


    if (ed_srchFixedAsetNo.getValue() > ed_srchFixedAsetNo2.getValue()) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_045);
        ed_srchFixedAsetNo.focus();
        return false;
    }

    return true;
}

