    scwin.f_FieldClear();
};

scwin.deprRtFormat = function (value) {
    return (Math.floor(value * 100) / 100).toFixed(2);
}

scwin.ed_srchFixedAsetNo_onblur = function (e) {
    if ($c.gus.cfIsNull(ed_srchFixedAsetNo.getValue()) == false)
        ed_srchFixedAsetNo.setValue($c.gus.cfGetLeftPad(ed_srchFixedAsetNo.getValue(), 10));
}

scwin.ed_srchFixedAsetNo2_onblur = function (e) {
    if ($c.gus.cfIsNull(ed_srchFixedAsetNo2.getValue()) == false)
        ed_srchFixedAsetNo2.setValue($c.gus.cfGetLeftPad(ed_srchFixedAsetNo2.getValue(), 10));
};
